import{_ as a,o as t,c as d,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Random Image API dan Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/random-image-api-and-public-gallery.md","filePath":"ms-MY/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"ms-MY/Other/random-image-api-and-public-gallery.md"};function n(o,e,l,s,c,p){return t(),d("div",null,[...e[0]||(e[0]=[i(`<h1 id="random-image-api-dan-public-gallery" tabindex="-1">Random Image API dan Public Gallery <a class="header-anchor" href="#random-image-api-dan-public-gallery" aria-label="Permalink to &quot;Random Image API dan Public Gallery&quot;">​</a></h1><p>Kedua-dua features dikonfigurasi di bawah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API return satu random file daripada selected directories. Ia berguna untuk site backgrounds, avatar rotation atau random image calls dari external pages.</p><p>Selepas diaktifkan, gunakan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Menghidupkan atau mematikan endpoint <code>/random</code>. Apabila disabled, access forbidden.</td></tr><tr><td>Directories</td><td>Mengehadkan directories yang boleh digunakan oleh random API. Directories yang tidak termasuk di sini tidak boleh digunakan oleh API.</td></tr><tr><td>Call demo</td><td>Menjana random API links yang boleh dicopy terus.</td></tr></tbody></table><p>Anda boleh memilih beberapa directories. Contohnya, jika hanya <code>/landscape/</code> dan <code>/portrait/</code> dibenarkan, random API hanya boleh memilih files daripada directories tersebut dan subdirectories.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Menentukan random directory.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Menentukan media type. Gunakan <code>image</code>, <code>video</code>, <code>audio</code> atau comma-separated combinations.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filter image orientation. Gunakan <code>portrait</code>, <code>landscape</code> atau <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format. Kosong bermaksud redirect, <code>url</code> return plain text URL, <code>json</code> return JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Digunakan dengan <code>type=url</code> untuk return full URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filter mengikut age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Hanya return files yang mengandungi tags ini.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Exclude files yang mengandungi tags ini.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>Tanpa <code>type</code>, API redirect terus ke random file URL.</p><p>Dengan <code>type=url</code>, ia return text URL.</p><p>Dengan <code>type=json</code>, ia return file information, termasuk file URL, file ID, file name, file type, tags, rating dan metadata berkaitan.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API mengikut public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Hanya files dalam allowed directories boleh dipilih.</td></tr><tr><td>Blocklist</td><td>Blocklisted files dikeluarkan daripada random pool.</td></tr><tr><td>Allowlist mode</td><td>Apabila enabled, hanya files yang allowed untuk public access akan return.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 dan content seumpamanya difilter mengikut current access mode.</td></tr></tbody></table><p>Jika tiada file match selepas filtering, API return no matching result.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API cache directory candidate pools untuk meningkatkan speed.</p><p>Selepas files berubah, ImgBed update directory cache version, dan requests kemudian rebuild candidate pool. Empty directories dicache seketika untuk mengelakkan repeated queries.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery menyediakan read-only public browsing page untuk directories yang anda benarkan visitors lihat.</p><p>Selepas diaktifkan, visitors boleh membuka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Menghidupkan atau mematikan public gallery. Apabila disabled, visitors tidak boleh browse.</td></tr><tr><td>Image loading mode</td><td>Mengawal sama ada previews menggunakan original images atau thumbnails.</td></tr><tr><td>Open directories</td><td>Menetapkan directories yang boleh diakses oleh visitors.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>Visitor page load original files secara langsung.</td></tr><tr><td>Thumbnail</td><td>Visitor page mengutamakan thumbnails untuk loading lebih laju.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories menentukan apa yang visitors boleh lihat.</p><p>Contoh:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors kemudian boleh mengakses:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories juga boleh dibuka, seperti <code>/2026/lucky/</code>. Visitors diblock daripada directories yang tidak open.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>Lihat files dan subdirectories dalam open directories.</td></tr><tr><td>Search</td><td>Search mengikut file name, file ID atau tags.</td></tr><tr><td>Type filter</td><td>Filter images, videos, audio atau other files.</td></tr><tr><td>Tag filter</td><td>Include atau exclude selected tags.</td></tr><tr><td>Orientation filter</td><td>Filter landscape atau portrait images.</td></tr><tr><td>Time filter</td><td>Filter mengikut upload time range.</td></tr><tr><td>Extension filter</td><td>Filter mengikut file extension.</td></tr><tr><td>Copy link</td><td>Copy file access links.</td></tr><tr><td>Media preview</td><td>Lihat atau mainkan images, videos dan audio pada visitor page.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery juga mengikut public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>Hanya allowed directories dipaparkan.</td></tr><tr><td>Access mode</td><td>Content difilter mengikut current age-rating access mode.</td></tr><tr><td>Allowlist mode</td><td>Apabila enabled, hanya files yang allowed untuk public access dipaparkan.</td></tr><tr><td>Blocklist</td><td>Blocklisted files disembunyikan.</td></tr></tbody></table>`,43)])])}const m=a(r,[["render",n]]);export{h as __pageData,m as default};
